var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"20년 전, 직할 도시 <color=#ffd34c>프론트베이</color>","JPN":"20年前、直轄都市<color=#ffd34c>フロントベイ</color>","ENG":"20 years ago, Administration Direct Control City, <color=#ffd34c>Front Bay</color>","TWN":"20年前，直轄城市<color=#ffd34c>前灣</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"금방이라도 무너져 내릴 것 같은 표정이네, 에이버리?","JPN":"今にも泣き出しそうな顔よ、エイバリー。","ENG":"You look like you're about to fall apart, Avery.","TWN":"艾維利，你的表情看起來隨時都要崩潰了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"그런 표정을 지으면 널 구해준 보니가 어떻게 눈을 감을 수 있겠니?","JPN":"そんな顔してたら、あなたを救ってくれたボニーが安らかに眠れないじゃない。","ENG":"If you make that face, how is Bonny supposed to rest easy?","TWN":"如果你露出那種表情，要救了你的寶妮怎麼瞑目呢？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"리드.","JPN":"リード。","ENG":"Read.","TWN":"里德。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"여기서 누구보다 내가 원망스러운 건 너일 텐데.","JPN":"この中で誰より私を恨んでいるのはお前だろうに。","ENG":"If anything, I'm the one you should resent most.","TWN":"在這裡，只有你比任何人都更有資格怨恨我。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"친한 동료를 나 때문에 잃은 것에 대해 화가 나지는 않나?","JPN":"大切な仲間が私のせいで犠牲になったのだ、恨めしくはないか？","ENG":"Aren't you angry that I caused the death of your close crewmate?","TWN":"我害你失去了親密的同伴，你不生氣嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"<color=#ffd34c>선장은 배는 버려도 선원은 버리지 않는다.</color>","JPN":"<color=#ffd34c>船長は船は捨てても船員は捨てない。</color>","ENG":"<color=#ffd34c>The captain may abandon the ship, but doesn't abandon the crew.</color>","TWN":"<color=#ffd34c>船長可以捨棄船，但絕不會丟下船員。</color>"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"당신은 당신의 말을 지켰으니, 보니도 보니의 말을 지켰을 뿐이야.","JPN":"あなたが自分の言ったことを守ったから、ボニーも自分の言ったことを守ったまでよ。","ENG":"You kept your word, so Bonny simply kept hers.","TWN":"你遵守了自己的承諾，寶妮也只是遵守了她的約定而已。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"참 당돌한 부함장이었어.","JPN":"本当に大胆な副艦長だった。","ENG":"You were always such a bold first mate.","TWN":"你真是個魯莽的副船長啊。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"감히 선장 명령을 어기고 기함의 제어권까지 가져갔으니 말이야.","JPN":"船長命令なんて無視して、旗艦の制御権まで持って行ったからな。","ENG":"You even disobeyed the captain's orders and seized control of the Flagship.","TWN":"竟敢違抗船長命令，還搶走旗艦的控制權。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"가려는 거야? 출항 준비를 하면 되는 걸까?","JPN":"行くの？　出航の準備をすればいいのかしら。","ENG":"You're leaving? Should I start preparing for departure?","TWN":"你要走了？那我是不是該準備起航了？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"새 배라면 어떻게든 구해볼 테니까…….","JPN":"新しい船なら、どうにか探してみる手はあるから……","ENG":"If it's a new ship you need, I'll find one somehow–","TWN":"我會想辦法弄來新船……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"난 관리국의 제안을 받아들일 생각이야.","JPN":"私は管理局の提案に乗るつもりだ。","ENG":"I'm going to accept the Administration's offer.","TWN":"我打算接受管理局的提案。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"……그렇구나.","JPN":"……そう。","ENG":"...I see.","TWN":"……這樣啊。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"관리국의 기함 <color=#ffd34c>인빈서블</color> 덕분에 그 괴물을 쓰러뜨리고 나서 깨달았어.","JPN":"管理局の旗艦<color=#ffd34c>インビンシブル</color>のおかげであの化け物を倒してから、悟ったんだ。","ENG":"After bringing down that monster thanks to the Administration's Flagship, <color=#ffd34c>Invincible</color>, I realized something.","TWN":"在靠管理局旗艦<color=#ffd34c>無敵號</color>擊倒那隻怪物後，我終於懂了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"이제 우리 힘만으로는 고향을 지킬 수 없다는 것을.","JPN":"これ以上、私たちの力だけでは故郷を守れないということを。","ENG":"We can't protect our home on our own anymore.","TWN":"我們已經無法只靠自己的力量守護家鄉。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니도 그걸 알아서 그런 선택을 내린 거겠지.","JPN":"ボニーもそれが分かったからあんな選択をしたのだろう。","ENG":"Bonny must have known that too. That's why she chose what she did.","TWN":"寶妮也是明白這點，才做出那樣的選擇吧。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"다른 선원들한테는 얘기해 뒀어.","JPN":"他の船員たちには話しておいた。","ENG":"I've already spoken with the others.","TWN":"我已經跟其他船員說了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"어떻게 받아들일지는 모르겠지만, 각자 생각이 있을 거다.","JPN":"どう受けとめるかはわからないが、みんな思うところがあるはず。","ENG":"I don't know how they'll take it, but everyone has their own thoughts.","TWN":"他們會怎麼想我不清楚，但每個人都有自己的選擇。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"리드. 넌 이제 어쩔 생각이지?","JPN":"リード、お前はこれからどうする？","ENG":"Read. What do you intend to do now?","TWN":"里德，你接下來打算怎麼辦？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"글쎄. 그 해군 아저씨나 다시 괴롭히러 가는 것도 괜찮겠는데?","JPN":"そうね。またあの海軍のおじさんを悩ませに戻るのも悪くないわね。","ENG":"Well, maybe I'll go bother that navy fellow again.","TWN":"嗯，再去找那個海軍大叔的麻煩也不錯？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"훗, 그 샌님이 꽤 재밌어 보인 모양이군.","JPN":"ふっ、あの堅物、相当からかい甲斐があったようだな。","ENG":"Haha. Seems that stuffy fellow piqued your interest.","TWN":"呵，看來你覺得那個書呆子很有趣嘛。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그래… 그게 너 다운 행동이지.","JPN":"そうだな……そうしている方がお前らしい。","ENG":"Yeah... that's just like you.","TWN":"的確……那很像你會做的事。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"좋아, 선장 명령이다.","JPN":"よし、船長命令だ。","ENG":"All right. Captain's orders.","TWN":"好，這是船長的命令。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"에이버리 해적단은 오늘로 해산.","JPN":"エイバリー海賊団は本日にて解散。","ENG":"The Avery Pirates are disbanded as of today.","TWN":"艾維利海盜團自今日起解散。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"사유는 선장 및 해적단 전원 실종이다.","JPN":"船長および海賊団全員の失踪が、その理由だ。","ENG":"Reason being the captain and all crew are missing.","TWN":"理由是船長與海盜團全員失踪。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"하지만… 그렇게 되면 <color=#ffd34c>그 아이</color>는 어떻게 할 생각이야?","JPN":"でも……そうなったら<color=#ffd34c>あの子</color>はどうするつもり？","ENG":"But... what about <color=#ffd34c>the girl</color>?","TWN":"但是……這樣的話你打算怎麼處理<color=#ffd34c>那孩子</color>？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"우리는 죽은 사람들이야, 리드.","JPN":"私たちは死んだんだ、リード。","ENG":"We're basically dead people, Read.","TWN":"我們已經是死人了，里德。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"사람들이 과거의 망령에 사로잡히지 않도록, 나는 얼굴을 가리고, 목소리를 변조하여 살아갈 생각이야.","JPN":"人々が過去の亡霊に囚われないよう、私は顔を隠し、声を変えて今後生きていくつもりさ。","ENG":"I'm gonna hide my face and change my voice, so people don't cling to the ghosts of the past.","TWN":"為了不讓大家被過去的亡靈束縛，我會遮住自己的臉、改變聲音活下去。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"<color=#ffd34c>그 아이</color>가 과거가 된 망령들과 지내게 할 수는 없어.","JPN":"<color=#ffd34c>あの子</color>をすでに過去のものとなった亡霊の元に置くわけにはいかない。","ENG":"I won't let <color=#ffd34c>her</color> spend her life among specters of a bygone era.","TWN":"我不能讓<color=#ffd34c>那孩子</color>跟過去的亡靈們一起生活。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그저… 마음이 이끄는 대로 자라길 바랄 뿐이야.","JPN":"ただ……心の赴くまま自由に育ってほしいんだ。","ENG":"I just... want her to grow the way her heart leads her.","TWN":"我只希望她……能順著自己的心活下去。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"그게 해적이잖아?","JPN":"それが海賊っていうものだろう？","ENG":"That's what being a pirate is, isn't it?","TWN":"那才是海盜不是嗎？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_AVERY","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"……그래, 선장.","JPN":"……わかったよ、船長。","ENG":"...Yes, Captain.","TWN":"……是，船長。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_NULL_SILHOUETTE","text":{"KOREA":"그게 당신의 마지막 명령이라면.","JPN":"それがあなたの最後の命令なら。","ENG":"If that's your final order.","TWN":"如果那是你最後的命令。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"subtitle","speaker":null,"text":{"KOREA":"5년 전","JPN":"5年前","ENG":"5 years ago","TWN":"5年前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>프론트베이</color> 관리국 본부","JPN":"管理局直轄都市<color=#ffd34c>フロントベイ</color>、管理局本部","ENG":"Administration Direct Control City, <color=#ffd34c>Front Bay</color>, Administration HQ","TWN":"管理局直轄城市<color=#ffd34c>前灣</color>管理局本部"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"subtitle","speaker":null,"text":{"KOREA":"프론트 베이 선상 반란","JPN":"フロントベイ船上反乱","ENG":"Front Bay Shipboard Rebellion","TWN":"前灣船上叛亂"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"subtitle","speaker":null,"text":{"KOREA":"발생 횟수 총 <color=#ffd34c>56</color> 회","JPN":"発生回数、合計<color=#ffd34c>56</color>回","ENG":"<color=#ffd34c>56</color> total incidents","TWN":"發生次數共<color=#ffd34c>56</color>次"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"녀석이 이번엔 관리국 본부로 들어갔다!","JPN":"やつめ、今度は管理局本部に入って行ったぞ！","ENG":"She's broken into the Administration HQ this time!","TWN":"那傢伙這次竟然闖進管理局本部了！"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"모든 무기를 동원해서 녀석을 제압해!","JPN":"武器を総動員して、やつを制圧しろ！","ENG":"Use everything we have and bring her down!","TWN":"動用所有武力制伏她！"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"상대는 고등급 카운터다! 무슨 짓을 벌일지 몰라!","JPN":"相手は高ランクカウンターだ！　何をしでかすかわからない！","ENG":"She's a high-grade Counter! We don't know what she'll do!","TWN":"對方是高等級制裁者！不知道她會做什麼！"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"다른 녀석들은 전부 제압을 완료했다!","JPN":"他のやつらは全員制圧済みだ！","ENG":"All the others have been subdued!","TWN":"其他人已經都制服了！"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 건 선상 반란의 주동자뿐이야!!","JPN":"残るは船上反乱の首謀者のみ！！","ENG":"The only one left is the rebellion's ringleader!!","TWN":"只剩下船上叛亂的主謀！！"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"대, 대장님! 조심하십쇼!","JPN":"た、隊長！　危険です！","ENG":"C-captain! Watch out!","TWN":"隊、隊長！請小心！"},"stage":{"bg":"FRONTBAY_IN","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"겨우 이 정도로 날 막으려고 하다니… 내가 너무 쉽게 보였나 보지?","JPN":"この程度であたしを止めようなんて……ずいぶんなめられたもんね。","ENG":"To think you tried to stop me with this pathetic effort... did I look that easy?","TWN":"竟然覺得這種程度能阻止我……你們是不是太小看我了？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"아니면… 너희 같은 떨거지들로는 나를 막을 수 없다는 걸 잘 알았다거나.","JPN":"それとも……お前らみたいな雑魚じゃあたしを止められないって分かってるから腰が引けてるのか？","ENG":"Or maybe... you just knew trash like you could never stop me.","TWN":"還是……你們自己也很清楚像你們這種小跟班根本擋不住我？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"개죽음당하기 싫으면 얼른 꺼져.","JPN":"犬死にしたくなければさっさと消えな。","ENG":"If you don't want to die for nothing, get lost.","TWN":"不想白白送命就快滾。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"난 시니어 목만 따면 되니까.","JPN":"あたしはシニアを殺れりゃそれでいいんだ。","ENG":"All I need is the Senior's head.","TWN":"我只需要取走那位Senior的頭。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"크으윽… 놈이 일으킨 지진 때문에 다가갈 수가 없어……!","JPN":"くううっ……やつが起こした地震のせいで近づけない……！","ENG":"Grgh... We can't get close because of the quake she's causing...!","TWN":"可惡……她引發的地震讓我們根本無法靠近……！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"대장님! 관리국 본부 주변 건물에도 영향이 가기 시작했습니다!","JPN":"隊長！　管理局本部周辺の建物にも影響が出始めています！","ENG":"Captain! The buildings surrounding the Administration HQ are starting to take damage!","TWN":"隊長！管理局本部周邊建築開始受影響了！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이 대치가 지속된다면… 프론트 베이 중심부가 폭삭 무너질 거예요!","JPN":"このまま対峙し続ければ……フロントベイ中心部が完全に崩壊するかもしれません！","ENG":"If this keeps up... the city center of Front Bay will collapse!","TWN":"再這樣僵持下去……前灣中心要整片垮了！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"그럼 저 테러리스트가 본부로 걸어 들어가는 걸 방치하라는 소리야?!","JPN":"では、あのテロリストが本部に入っていくのを黙って見ていろと言うのか！？","ENG":"So you're telling me we should just let that terrorist walk right into HQ?!","TWN":"那你是要叫我放任那個恐怖分子走進本部嗎？！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"지난번에는 해일을 몰고 와서 겨우 자리를 잡아가던 5 섹터의 격벽을 몽땅 부숴버렸어.","JPN":"この前なんて津波まで起こして、やっと安定し始めていたセクター5の隔壁をぶち壊したんだぞ。","ENG":"Last time she brought in a tidal wave and smashed the whole bulwark in Sector 5.","TWN":"上次她引發海嘯，把才剛恢復的第5區隔牆都砸爛了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"거기서 해방된 죄수들을 선동해 우리를 관리국 본부까지 몰아넣었다고!","JPN":"それから、そこで解放された囚人たちを扇動して、私たちを管理局本部まで追い込んだんだ！","ENG":"She rallied the freed inmates and drove us all the way back to HQ!","TWN":"甚至煽動逃出的囚犯，把我們一路逼到管理局本部！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"이대로면 프론트 베이 관리국은 끝장이야!","JPN":"このままではフロントベイ管理局は終わりだ！","ENG":"At this rate, the Front Bay Administration is finished!","TWN":"照這樣下去，前灣管理局會完蛋的！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"잘 알고 있네. 너희 프론트 베이 관리국은 오늘부로 끝이라는 거.","JPN":"よくわかってるじゃねえか。お前らフロントベイ管理局は今日で終わりだってな。","ENG":"You understand perfectly. The Front Bay Administration ends today.","TWN":"你很清楚嘛。前灣管理局，到今天就結束了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"1분 준다.","JPN":"1分くれてやる。","ENG":"You've got one minute.","TWN":"我給你們1分鐘。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"땅속에 생매장되고 싶지 않으면 꺼져.","JPN":"土の下に生き埋めになりたくなければさっさと消えな。","ENG":"If you don't want to be buried alive, get out.","TWN":"不想被活埋就給我滾。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"크으윽… 지원은… 지원은 아직인가?","JPN":"くううっ……支援は……支援はまだなのか？","ENG":"Grgh... The reinforcements... where are they?!","TWN":"可惡……支援……支援還沒到嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"이번 선상 반란은 도시 전역에서 일어날 정도로 규모가 큽니다.","JPN":"今回の船上反乱は都市全域で大規模に発生しています。","ENG":"This rebellion is citywide, sir.","TWN":"這次船上叛亂的規模遍及全城。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"다른 지원 병력도 각 구역의 반란 분자들을 막고 있어서…….","JPN":"他の支援兵力も、各区域の反乱分子を制圧していますので……","ENG":"All available units are tied up containing insurgents across the sectors...","TWN":"其他支援兵力也在各區壓制叛亂者……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_NPC_ADMIN_NULL","text":{"KOREA":"제기랄…….","JPN":"クソ……","ENG":"Damn it...","TWN":"可惡……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"1분 끝.","JPN":"1分経った。","ENG":"Time's up.","TWN":"1分鐘到了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"그럼 잘 있어, 관리국의 개들아.","JPN":"じゃあな、管理局の犬ども。","ENG":"Well then... goodbye, Administration dogs.","TWN":"那就再見了，管理局的走狗們。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"응? 멀쩡하잖아?","JPN":"うん？　なんで何も起きない？","ENG":"Huh? Still standing?","TWN":"嗯？什麼事都沒發生？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_QM","text":{"KOREA":"대인 위상 방벽 활성화. 포트리스 실드 전개.","JPN":"対人位相防壁活性化。フォートレスシールド展開。","ENG":"Activating phase barrier. Deploying the fortress shield.","TWN":"對人相位屏障啟動。堡壘護盾展開。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_TECH_12"},{"id":"L11_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"마스터 칸이 이번엔 또 무슨 핑계로 이곳에 왔나 했는데…….","JPN":"マスター・カン、今回はどういう口実でここに来たのかと思いましたが……","ENG":"I was wondering what excuse Master Khan came up with to show up here...","TWN":"原來是坎大師啊，我還想說你這次又找什麼藉口跑來……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"이런 이유가 있었으면 진작 말씀하시면 좋지 않습니까?","JPN":"こんな理由があったならもっと早く話してくださってもよかったのでは？","ENG":"If there was a reason like this, you could've told me sooner.","TWN":"有這種原因的話你早點告訴我不好嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하하! 그러면 절차가 복잡해지지 않나?","JPN":"はは！　それでは手続きが面倒になるじゃろう。","ENG":"Haha! Then we'd have had to go through official procedure, no?","TWN":"哈哈！那樣流程不會變麻煩嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이곳에서 우연히 발견한 아티팩트를 조사하러 파견되었다가 고등급 카운터 범죄자와 조우했다.","JPN":"ここで偶然発見されたアーティファクトを調査するために派遣され、高ランクカウンターの犯罪者と遭遇した。","ENG":"We were dispatched to inspect an Artifact discovered nearby and happened to encounter a high-grade criminal Counter.","TWN":"我只是剛好被派來調查在附近發現的遺物，結果遇到高等級制裁者罪犯。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이만큼 둘러대기 쉬운 이유도 없지.","JPN":"これほど都合の良い言い訳もあるまい。","ENG":"Couldn't ask for a cleaner excuse.","TWN":"這理由多好啊？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"하아, 오래 막을 수는 없을 겁니다.","JPN":"はあ、私でも長くは食い止められません。","ENG":"*Sigh* We won't be able to hold off for long.","TWN":"唉，我撐不了太久。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"보아하니, 저쪽도 실력이 만만치 않은 것 같은데…….","JPN":"あちらもなかなかの腕前のようですし……","ENG":"Judging by the looks of it, that one's no pushover...","TWN":"我看她的實力也不簡單……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"저와 충돌한다면 그 여파가 주변까지 퍼질 테니까요.","JPN":"私と衝突すればその余波が周辺まで広がってしまいます。","ENG":"If I clash with her, the shockwaves will spread through the whole area.","TWN":"如果和我硬碰硬，衝擊會波及到周圍。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"잠깐이면 충분해.","JPN":"少しで十分じゃ。","ENG":"A moment is enough.","TWN":"只要一下子就好。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이쪽 시니어도 뭔가 준비하고 있는 것 같으니까.","JPN":"こっちのシニアも何か手があるようだからのう。","ENG":"Our Senior seems to have something prepared as well.","TWN":"我們這邊的Senior好像也有準備。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"잡담은 끝났냐, 노인네?","JPN":"無駄話は済んだか？　ジジイ。","ENG":"Done chatting, old man?","TWN":"聊完了嗎，老頭？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"노인네 패는 취미는 없으니까 옆에 찌그러져 있어.","JPN":"ジジイを殴る趣味はないんだ。引っ込んでな。","ENG":"I'm not in the habit of beating up geezers, so stay out of the way.","TWN":"我可沒有毆打老人的嗜好，你給我乖乖靠邊站。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"너, 딱 봐도 강해 보이는데… 왜 관리국의 도사견 따위가 되어 있는 거야?","JPN":"お前、かなり強そうだけど……なんで管理局の犬なんかやってるんだ？","ENG":"You look strong enough... So why lower yourself to being the Administration's lapdog?","TWN":"你看起來挺強的嘛……為什麼要當管理局的看門狗？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"범죄자는 이해할 수 없겠지.","JPN":"犯罪者にはわからないだろうな。","ENG":"A criminal wouldn't understand.","TWN":"罪犯當然無法理解。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"무언가를 지키기 위해 싸운다는 것을.","JPN":"何かを守るために戦うということが。","ENG":"Fighting to protect something important.","TWN":"為了守護某些人而戰鬥的理由。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"……?","JPN":"……？","ENG":"...?","TWN":"……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"뭐래. 그럼 먼저 때린다?","JPN":"意味わかんねーけど。　そんじゃ、こっちから先に行かせてもらうぜ。","ENG":"Whatever. I'll hit you first then.","TWN":"你在說什麼啊？那我就先出手囉？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"정말 도시를 무너뜨릴 기세로군.","JPN":"本気で都市を崩壊させるつもりのようじゃな。","ENG":"She really is shaking the whole city apart.","TWN":"你還真有摧毀整座城市的氣勢啊。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"웨이드와 호각으로 싸우는 카운터라니… 허허.","JPN":"ウェイドと互角に戦えるカウンターか……ホホ。","ENG":"To be evenly matched with Wade... Haha.","TWN":"能和韋德打成平手的制裁者……呵呵。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"어쩌면 저 아이는…….","JPN":"もしかしたらあの子は……","ENG":"Perhaps that child is–","TWN":"也許那孩子……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"정말 대단하지 않습니까?","JPN":"本当にすごいと思いませんか？","ENG":"Impressive, isn't she?","TWN":"真的很了不起吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"바다에선 해일을, 땅에선 지진을 일으킵니다.","JPN":"海では津波を、陸では地震を起こすんです。","ENG":"At sea she calls the waves, and on land she summons quakes.","TWN":"能在海上引起海嘯，在陸上能引發地震。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"이 프론트 베이를 살아감에 있어서 신과도 같은 능력이죠.","JPN":"このフロントベイで生きるにあたって、神に等しい能力でしょう。","ENG":"A godlike power for living in Front Bay.","TWN":"活在這個前灣，簡直就是神一般的力量。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"READ_NPC_NULL_QM","text":{"KOREA":"그걸 좀 더 세상을 위해 썼으면 좋았을 테지만…….","JPN":"それをもっと世のために使ってくれればよかったのですが……","ENG":"Would've been nice if she used it for the world instead...","TWN":"如果能把力量用在這個世界就好了……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"무얼, 다 자네의 묵인하에 방치되고 있는 것 아닌가?","JPN":"何を言うか、どうせ全部おぬしの黙認の元で放置しておるんじゃろう？","ENG":"Aren't you letting this all happen under your watch?","TWN":"這不都是在你的默許下才放著不管嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"시니어 잭.","JPN":"シニア・ジャック。","ENG":"Senior Jack.","TWN":"Senior傑克。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 프론트 베이에 고분고분한 사람은 살아남을 수 없으니까요.","JPN":"ハハハ！　従順な性格だと、フロントベイでは生き残れませんからね。","ENG":"Gah hah hah! Nobody meek survives in Front Bay!","TWN":"哈哈哈！聽話的人在前灣活不下去嘛。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"긴급 지원 요청에 응해주셔서 감사합니다, 시니어 칸.","JPN":"緊急支援要請にお応えいただきありがとうございます、シニア・カン。","ENG":"Thank you for responding to our emergency request, Senior Khan.","TWN":"感謝你回應緊急支援，Senior坎。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"저희 쪽도 이제 막 준비가 끝난 참이었거든요.","JPN":"こちらもやっと準備が終わったところです。","ENG":"We've just finished our preparations as well.","TWN":"我們這邊剛剛也準備好了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"벨라미! 정신 교란 재머를 발동시켜!","JPN":"ベラミー！　精神攪乱ジャマーを発動させろ！","ENG":"Bellamy! Activate the Mind Jammer!","TWN":"貝拉米！啟動精神干擾器！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"알겠습니다! 웨이드씨, 물러나세요!","JPN":"わかりました！　ウェイドさん、下がってください！","ENG":"Understood! Mr. Wade, fall back!","TWN":"我知道了！韋德，請後退！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"카운터 제압용 정신 교란 재머! 발동합니다!","JPN":"カウンター制圧用の精神攪乱ジャマー！　発動します！","ENG":"Activating the Counter-suppression Mind Jammer!","TWN":"制伏制裁者專用精神干擾器！啟動！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"윽! 이까짓 잔재주로 날 막을 수 있을 것 같아?!","JPN":"うっ！　こんな小細工であたしを止められると思ったのか！？","ENG":"Ngh! You think cheap tricks like this can stop me?!","TWN":"呃！你們覺得這種小把戲能阻止我？！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"후우, 확실히 강한 자로군요.","JPN":"ふう、確かに強いですね。","ENG":"Whew... She's certainly strong.","TWN":"呼……確實很厲害。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"정신 교란 재머로 능력이 제한된 상태에서도 이 정도의 힘을 방출하다니…….","JPN":"精神攪乱ジャマーで能力が制限されているにも、これほどの力を放つとは……","ENG":"Even with her powers suppressed by the Mind Jammer, she can output this much...","TWN":"能力在精神干擾器受限的狀態下還能釋放這種力量……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이럴 줄 알고 카운터 제압용 사슬도 준비해 뒀네.","JPN":"こうなると思って、カウンター制圧用の鎖も用意してある。","ENG":"Which is why I prepared Counter-suppression chains too.","TWN":"我就知道會這樣，所以準備了制伏制裁者專用的鎖鏈。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_1"},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"문제라면 저렇게 날뛰는 녀석의 팔다리를 어떻게 구속하냐는 거지만.","JPN":"問題はあれほど暴れているやつの手足をどうやって拘束するかだが。","ENG":"Only problem is... restraining a limb-flailing wildcat like that.","TWN":"問題是要怎麼抓住那種到處亂竄傢伙的四肢呢？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그거라면 저에게 맡겨주시죠.","JPN":"それなら私にお任せください。","ENG":"Leave that to me.","TWN":"那種事就交給我吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"고양이 목에 방울 달기라면 마스터 칸과 여러 곳을 돌아다니며 많이 해본 짓이거든요.","JPN":"猫の首に鈴を付けるのは、マスター・カンとあちこちを回りながら何度もやっていますから。","ENG":"Master Khan and I have hung the bell on more than a few cats in our time.","TWN":"我跟著坎大師到處跑時幫貓戴過不少次鈴鐺了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허, 이거 원, 쑥스럽구먼.","JPN":"ホホ、これはこれは、照れるのう。","ENG":"Hahaha, now that's embarrassing.","TWN":"呵呵，真讓人不好意思。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"칭찬 아닙니다.","JPN":"褒めているわけではありません。","ENG":"Not a compliment.","TWN":"那不是稱讚你。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"그럼, 적당한 타이밍에 구속 사슬을 채우도록 하겠습니다.","JPN":"では、適切なタイミングで拘束の鎖をつけます。","ENG":"I'll bind her the moment I see an opening.","TWN":"那麼，我會抓準時機套上拘束鎖鏈。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"누가 얌전히 제압당해 준대?!","JPN":"誰が大人しく制圧されてやるもんか！","ENG":"Who said I'd let you?!","TWN":"誰會乖乖被你們制服啊？！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"각오하라고.","JPN":"覚悟しとけよ。","ENG":"Get ready.","TWN":"覺悟吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_QM","text":{"KOREA":"크으윽… 이거… 놔!","JPN":"くううっ……放……せ！","ENG":"Krrgh... let... go!","TWN":"呃啊……這個……放開！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_2"},{"id":"L35_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"후우, 조금이라도 빈틈이 보였다면 제 머리통이 날아갔겠군요.","JPN":"ふう、少しでも隙を見せていたら、私の頭が飛ばされるところでした。","ENG":"Whew... If I'd slipped even once, my head would've been gone.","TWN":"呼……只要我露出一點破綻，腦袋大概就沒了吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"아직 전투 경험이 부족해 보여서 다행입니다.","JPN":"戦闘経験が足りないようで何よりです。","ENG":"She's still lacking real combat experience, lucky for us.","TWN":"看來她缺乏實戰經驗，真是不幸中的大幸。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 관리국 공인 카운터를 애먹게 하는 재능이라니, 놀랍지 않나?","JPN":"ハハハ！　管理局公認カウンターをも手こずらせる才能とは、すごくないか？","ENG":"Gah hah hah! A talent that can give an Official Administration Counter trouble. Amazing, isn't it?","TWN":"哈哈哈！她的天賦讓管理局公認制裁者這麼頭痛，能不驚人嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"글쎄요… 묘하게 뿌듯해하시는 것 같습니다만…….","JPN":"さあ……それにしても、妙に誇らしげですね……","ENG":"Well... You seem oddly proud, sir...","TWN":"唔……你看起來很滿意啊……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"설마, 관리국 본부를 거의 궤멸시킬 뻔한 범죄자인걸?","JPN":"まさか、管理局本部を壊滅寸前まで追い込んだ犯罪者だぞ。","ENG":"As if! She's a criminal who nearly wiped out the whole HQ!","TWN":"拜託，她可是差點毀掉管理局本部的罪犯欸？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"벨라미, 피해 규모가 어떻게 되지?","JPN":"ベラミー、被害の規模は？","ENG":"Bellamy, damage report?","TWN":"貝拉米，受損情況怎麼樣？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"관리국 본부는 다행히 피해가 크지 않습니다만, 그 주변 구역의 피해가 막심합니다.","JPN":"管理局本部は幸いにして大きな被害はありませんが、その周辺区域の被害が甚大です。","ENG":"The Administration HQ is mostly intact, but the surrounding districts took heavy damage.","TWN":"幸好管理局本部沒有太大損傷，但周邊區域的破壞相當嚴重。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"아, 지난번 건설 도중 파괴된 5 섹터의 격벽은 미리 보고드렸죠?","JPN":"あ、この前、建設の途中に破壊されたセクター5の隔壁についてはすでに報告済みですよね？","ENG":"Ah, Sector 5's bulwark that got destroyed during construction, I reported that already.","TWN":"啊，上次施工時被摧毀的第5區隔牆，我之前已經報告過了吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"키이라… 라고 했던가?","JPN":"キーラ……といったか？","ENG":"Kiera... was it?","TWN":"她是叫……琪伊拉嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네, 그렇습니다.","JPN":"はい、そうです。","ENG":"Yes, that is correct.","TWN":"對，沒錯。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 외에 특이 사항이 있나?","JPN":"他に特記事項はあるか？","ENG":"Anything else unusual?","TWN":"除此之外還有其他特殊事項嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"크루 가문이 후원하던 보육원 출신으로, 이 시대의 대해적이 되겠다 주장하고 있습니다.","JPN":"クルー家が後援していた孤児院の出身で、この時代の大海賊になると言い張っているようです。","ENG":"An orphanage kid sponsored by the Crew family who claims she'll be a great pirate of this era.","TWN":"她出身於克盧家族資助的孤兒院，主張要成為這個時代的大海盜。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"……어처구니없군.","JPN":"……ばかなことを。","ENG":"...Ridiculous.","TWN":"……真荒謬。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대해적이 된다는 게 무슨 의미인 줄은 알고 그런 소리를 하는 건가?","JPN":"大海賊になるというのがどういう意味か、わかって言ってるのか？","ENG":"Does she even understand what becoming a great pirate means?","TWN":"妳知道成為大海盜是什麼意思嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"당연하지.","JPN":"当たり前だ。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리의 의지를 이어받아, 해적들에게 자유를 돌려줄 사람.","JPN":"エイバリーの意志を受け継ぎ、海賊に自由を取り戻してやる人。","ENG":"Someone who will inherit Avery's will and return freedom to the pirates.","TWN":"我是要繼承艾維利的意志，把自由還給海盜的人。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ONLY_CHARADE_C_CRIMSON_CHAIN_2"},{"id":"L9_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"관리국에 빼앗긴 자유를 되찾아주는 사람이 대해적이야.","JPN":"管理局に奪われた自由を取り戻してやる人が大海賊だ。","ENG":"A great pirate is someone who takes back the freedom the Administration stole.","TWN":"奪回被管理局奪走的自由之人，就是大海盜。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리의 의지라… 그렇군…….","JPN":"エイバリーの意志か……なるほど……","ENG":"Avery's will... I see...","TWN":"艾維利的意志啊……原來如此……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하나 충고하지.","JPN":"1つ忠告する。","ENG":"Let me give you some advice.","TWN":"我給妳一個忠告。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그런 식으로는 영원히 대해적이, 아니, 그럴듯한 해적조차 될 수 없을 거야.","JPN":"こんなやり方では永遠に大海賊、いや、海賊にすらなれないぞ。","ENG":"At this rate you'll never become a great pirate– No, not even a half-decent one.","TWN":"照妳現在的方式，永遠不可能成為大海盜。不，連像樣的海盜都當不了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"바다는 목적이 없는 얼간이를 집어삼키는 걸 좋아한다.","JPN":"海は目的を持たない愚か者を飲み込むことが好きなんだ。","ENG":"The sea loves swallowing fools without purpose.","TWN":"大海最喜歡吞噬沒有目標的蠢貨了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 아가씨는… 바다가 집어삼키기 딱 좋은 먹잇감이로군.","JPN":"今のお嬢さんは……海が飲み込むにはちょうどいい獲物だな。","ENG":"And right now... you're the perfect meal.","TWN":"現在的妳……就是最適合被吞噬的獵物。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 자식이… 네가 뭘 안다고……!","JPN":"この野郎……お前に何がわかる……！","ENG":"You bastard... what do you know...?!","TWN":"這傢伙……你懂什麼……！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L23_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"큭! 이거… 놔!!","JPN":"くっ！　……放せ！！","ENG":"Kgh! L-let me... go!!","TWN":"可惡！這個……放開我！！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"후우, 구속구가 끊어졌군요.","JPN":"ふう、拘束具が壊れてしまいましたね。","ENG":"Whew... The restraints snapped.","TWN":"呼，束具被扯斷了啊。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"WADE_CAMPAMENTO_NULL_NULL","text":{"KOREA":"또 다른 구속구를 채워봤자, 소용없을 것 같은데… 다른 방법은 없습니까?","JPN":"つけ直したところで無駄だと思いますが……他に方法はないのですか？","ENG":"Even if we put new ones on her, they'll just break again... Any other ideas?","TWN":"再套上新的也沒用吧……還有別的方法嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WADE_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"방법이 없는 건 아니에요.","JPN":"方法がないわけではありません。","ENG":"There is one way.","TWN":"也不是沒有方法。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"구 관리국의 기술력으로 만들어진 특수 제어 구속구라면…….","JPN":"旧管理局の技術力で作られた特殊制御拘束具なら……","ENG":"If we use the Old Administration's special restraints...","TWN":"如果使用舊管理局技術打造的特殊控制束具……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"키이라의 출력을 억제할 수 있습니다.","JPN":"キーラの出力を抑制することができます。","ENG":"We can suppress her output.","TWN":"就能壓制琪伊拉的輸出。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다행이군. 하지만 이 방법을 지금에서야 꺼냈다는 건…….","JPN":"朗報だな。だが、その方法を今になって出してきたということは……","ENG":"Good. But if you're only mentioning this now, that must means...","TWN":"那就好。不過你現在說出這個方法，就表示……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"네. 이 구속구는 관리국 오퍼레이팅 시스템의 통제를 받습니다.","JPN":"はい。この拘束具は管理局オペレーティングシステムによって統制されます。","ENG":"Yes. These restraints are linked to the Administration's operating system.","TWN":"對，這束具受管理局標準作業系統控制。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"즉, 제가 직접 출력을 제어, 조절하는 방식이에요.","JPN":"つまり、私が直接出力を制御・調節する方法なのです。","ENG":"Meaning I'll have to manually monitor and adjust her output.","TWN":"也就是要由我親自調節、抑制她的力量。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"특수 이터니움 합금으로 만들어졌으니 끊어질 일도 없죠.","JPN":"特殊エタニウム合金で作られているので、壊れることもありません。","ENG":"They're made of special Eternium alloy, so they won't break.","TWN":"那是用特殊的永恆之金合金打造，基本上不會被破壞。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"지속적으로 제어를 확인해야 한다는 귀찮음만 제외한다면, 지금으로선 이게 최선이네요.","JPN":"制御に不具合はないか常時確認する手間を除けば、今ある中ではこれがベストでしょう。","ENG":"Aside from constantly monitoring her control levels, it's our best option.","TWN":"撇除需要持續監控的麻煩，對現在來說算是最好的選擇了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"물론… 그것도 범죄자를 아케론으로 수감시킨다면 그만인 이야기지만요.","JPN":"もちろん……犯罪者をアケロンに収監するなら必要のない話ですが。","ENG":"Of course... we could just send that criminal to Acheron.","TWN":"當然……要是直接把罪犯關進黃泉就什麼事都沒有了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아케론이라… 카운터 범죄자들의 종착점이지.","JPN":"アケロンか……カウンター犯罪者の終着駅だな。","ENG":"Acheron... the final stop for criminal Counters.","TWN":"黃泉嗎……那可是制裁者罪犯的終點。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다른 녀석들에게 아주 좋은 본보기가 되겠어.","JPN":"他のやつらの見せしめには良さそうだ。","ENG":"A fine example to set for the others.","TWN":"也能給其他傢伙好好做個榜樣。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자네, 아케론에 보낼 생각이 없구먼?","JPN":"おぬし、アケロンに送るつもりはないな？","ENG":"You have no intention of sending her to Acheron, do you?","TWN":"你果然不想把她送去黃泉吧？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"표정을 볼 순 없지만, 자네의 어깨가 미세하게 들썩거리고 있어.","JPN":"おぬしの顔は見えないが、少し肩をそびやかしておる。","ENG":"Can't see your face, but your shoulders are twitching.","TWN":"雖然我看不到你的表情，但你的肩膀在微微顫抖。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"우리를 골탕 먹일 재밌는 생각을 하는 중이라면, 지금 알려주게.","JPN":"ワシらを困らせて楽しもうと考えているのなら、今すぐ教えるんじゃな。","ENG":"If you're cooking up some scheme to mess with us, speak now.","TWN":"如果你正打算想什麼鬼主意讓我們頭痛，現在就說出來吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫! 역시 시니어 칸의 눈썰미는 대단하시군요.","JPN":"ハハハ！　シニア・カンの目は誤魔化せないですね。","ENG":"Gah hah hah! As expected of Senior Khan. Sharp as ever.","TWN":"哈哈哈！不愧是Senior坎，果然眼力了得。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"세계 제일의 트레저 헌터답습니다.","JPN":"さすがは世界一のトレジャーハンターだ。","ENG":"Truly the world's greatest treasure hunter.","TWN":"不愧是世界第一的尋寶獵人。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"때마침 프론트 베이의 공인 카운터가 부상으로 요양 중이라서 말이죠.","JPN":"ちょうどフロントベイの公認カウンターが怪我で療養中でしてね。","ENG":"And as luck would have it, Front Bay's Official Counter is recovering from an old injury.","TWN":"正好前灣的公認制裁者正在療傷。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"저 힘을 썩히기는 아깝지 않습니까?","JPN":"あの力を腐らせてしまうには惜しいと思いませんか？","ENG":"Would be a waste not to use talent like hers.","TWN":"讓那股力量荒廢不是太可惜了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"시니어님! 설마……?","JPN":"シニア様！　まさか……？","ENG":"Senior! You're not...?!","TWN":"S、Senior！你該不會……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"키이라를 카운터 범죄자를 가두기 위해 만든 특수 독방에 수감시켜.","JPN":"キーラをカウンター犯罪者専用の特殊独房に収監しろ。","ENG":"Confine Kiera in the special isolation cell built for criminal Counters.","TWN":"把琪伊拉關押至專門監禁制裁者罪犯的特殊單人牢房。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"정신 교란 재머의 출력은 최대로, 죄수의 출력 제어는 벨라미, 자네가 수고해 줘.","JPN":"精神攪乱ジャマーの出力は最大に、囚人の出力制御はベラミー、君が頑張ってくれ。","ENG":"Set the Mind Jammer to maximum. Bellamy, you handle output control.","TWN":"精神干擾器輸出全開，罪犯的輸出控制就交給你了，貝拉米。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"너무 위험해요. 시니어님의 마음은 백번 이해합니다만…….","JPN":"危険すぎます。シニア様のお心は十分理解しますが……","ENG":"It's too dangerous, sir. I understand your feelings, but still...","TWN":"太危險了。我能理解Senior的想法，但是……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이대로 아케론에 보내면 저 아가씨는 극악무도한 카운터 범죄자로 끝날 거야.","JPN":"このままアケロンに送れば、あのお嬢さんは一生「極悪非道なカウンター犯罪者」のままで終わってしまう。","ENG":"If we send her to Acheron now, that girl will become nothing but a monstrous criminal Counter.","TWN":"若是直接送去黃泉，那女孩的人生只會作為犯下滔天大罪的制裁者罪犯結束。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 프론트 베이에 남아 있다면 언젠가는…….","JPN":"だがフロントベイに残っていれば、いつかは……","ENG":"But if she stays in Front Bay, then someday...","TWN":"可若留在前灣，總有一天……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"자신이 표류하고 있는 드넓은 바다에서 길을 찾을지도 모르는 일 아니겠나?","JPN":"自分が漂流している広大な海で、道を見つけるかもしれないだろう？","ENG":"She might find her way across the vast sea she's drifting in.","TWN":"說不定她能在自己漂流的這片大海中找到方向。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"표류하고 있다고?","JPN":"漂流しているだって？","ENG":"Drifting?","TWN":"漂流？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"여기서 나만큼 자유롭게 항해를 하고 있는 사람이 어디 있다는 거야?!","JPN":"ここであたしほど自由に航海しているやつなんかいない！","ENG":"Who here sails more freely than I do?!","TWN":"這世界上誰能比我更自在航行？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"다시 말하지만, 아가씨는 해적이 아니야.","JPN":"もう一度言っておくが、お嬢さんは海賊ではない。","ENG":"Again, you're no pirate.","TWN":"我再說一遍，妳不是海盜。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"자신의 힘을 무분별하게 분출하는 무뢰배일 뿐이지.","JPN":"自分の力を分別なく噴出する、ただのならず者だ。","ENG":"You're just a reckless thug blasting your power everywhere.","TWN":"妳只是亂用力量的無賴而已。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"뭐, 그런 뒤가 없는 모습조차 닮았을지도 모르겠군.","JPN":"まあ、その刹那に生きるところも似ているのかもしれないな。","ENG":"Though... that part might resemble someone I knew.","TWN":"不過嘛，說不定連妳這種不顧後果的樣子都很像呢。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그게 무슨……?","JPN":"それはどういう……？","ENG":"What's that supposed to mean...?","TWN":"那是什麼意思……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그럼, 때가 되면 다시 보도록 하지.","JPN":"では、時がくればまた会おう。","ENG":"We'll meet again when the time is right.","TWN":"那麼，就等時間到了再見吧。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그때까진… <color=#ffd34c>안전하게</color> 지내도록 해.","JPN":"それまでは……<color=#ffd34c>安全に</color>過ごすんだ。","ENG":"Until then... stay <color=#ffd34c>safe</color>.","TWN":"在那之前……給我<color=#ffd34c>乖乖</color>待著。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};